}

type ManagerCompactionStatus struct {
    Started      bool   `json:"started"`
    Reason       string `json:"reason,omitempty"`
    UsagePercent string `json:"usagePercent,omitempty"`
    HandoffPath  string `json:"handoffPath,omitempty"`
