	}
}

func TestManagerCompactionThresholdWritesHandoffAndMarksCompacting(t *testing.T) {
	fixture := newManagerFlowFixture(t)
	stateFile := filepath.Join(fixture.stateRoot, "state.json")
	usage := 81.0
	state := ManagerState{
		CanonicalPlanDir: fixture.planDir,
